import{_ as a,c as t,ah as p,o as r}from"./chunks/framework.B8QGmHkS.js";const c=JSON.parse('{"title":"公无渡河","description":"","frontmatter":{"layout":"post","title":"公无渡河","date":"2023-08-05 13:00:00 +0800"},"headers":[],"relativePath":"writing/2023/2023-08-05-the-river.md","filePath":"writing/2023/2023-08-05-the-river.md"}'),i={name:"writing/2023/2023-08-05-the-river.md"};function o(n,e,s,l,h,_){return r(),t("div",null,e[0]||(e[0]=[p('<h2 id="一、凤凰台" tabindex="-1">一、凤凰台 <a class="header-anchor" href="#一、凤凰台" aria-label="Permalink to &quot;一、凤凰台&quot;">​</a></h2><p>凤凰台上凤凰游，凤去台空江自流。据说李白到了黄鹤楼的时候，看到了崔颢的题诗，大为叹服，竟搁笔而去。后来李白流放夜郎遇赦返回，登金陵凤凰台，写下了这样的句子，与前者遥遥相应。无论是传说中驾黄鹤的仙人，还是那个带着小姨子远走高飞的黄鹤老板，最终都是一去不复返了。吴宫花草，晋代衣冠，最终也是淹没在了历史洪流中，化为尘土。不知道李白在写这首诗的时候，到底是怎样的心情呢，究竟是看得开了，还是没看得开。窃以为他是没有看开，不然也就不会说使人愁了。</p><p>当然这很正常，毕竟我们绝大多数人，都喜欢勉强自己。比如明明活得很痛苦了，却还要强颜欢笑；明明不喜欢一些人一些事，却还要口是心非；明明在意的，却要表现出无所谓。所谓的世界以痛吻我，我却报之以歌，颇有点以德报怨的意味在里面。但果真如此吗？</p><p>据说大抵少年不知道愁滋味，却还是喜欢为赋新词强说愁。记得很小的时候就有同学喜欢叼着根烟，留一头沧桑的发型，吞云吐雾，仿佛自己已经度过了漫长的人生。当然这现在看起来是很可笑的一件事情。记得自己少年时也曾模仿写过“从来欢愁人不知，古今荣辱皆成丘”这样的句子，现在看来也一样可笑，毕竟当时也没有经历过什么真正的欢愁和宠辱。</p><p>当然，用现在的眼光去看过去，是有些事后诸葛亮的。现在的自己看过去，和若干年后的自己看现在，大抵是差不多的。对过去的自己，以及自己的过去指指点点，然而当下的自己却没有了彼时年少轻狂的蓬勃生气，其实是让人唾弃的。</p><p>走在路上的时候，我看到装满工业燃料的油罐车，想到了每天上下班拥挤的地铁，想到了狭小笼子里每天下蛋的老母鸡，想到了自己。我这个人，有时候就是容易想得太多。人想得太多，就不容易开心起来。记得还在故乡读书的时候，喜欢骑着车子飞驰在空寂无人的马路上，路边是柳树混合着青草的气味，当时的自己也不开心，因为脑子里想的都是要好好学习，考个好大学，开启新的人生。那时的自己根本不会意识到油罐车，地铁，还有老母鸡。现在看起来的话，其实也说不上到底是当时还是现在更快乐，或者当时还是现在更痛苦。反正日子就这样一天天过来了。</p><p>扯得远了。我没有去过黄鹤楼，也没有登过凤凰台，也只登过其它高楼或高台。炎炎夏日，登高远眺，然后寻一条清静的小巷，优哉游哉晃荡过去，这种欣喜难抑的心情，估计是再难有了。</p><h2 id="二、七月" tabindex="-1">二、七月 <a class="header-anchor" href="#二、七月" aria-label="Permalink to &quot;二、七月&quot;">​</a></h2><p>一切过去的都不会再有了。李贺说，唯见月寒日暖，来煎人寿。</p><p>总觉得，欢娱短暂，苦痛漫长。以前遇到问题，总想着交给时间就好了。反正到了特定的某个时刻，一切都会解决。现在想起来，其实是因果倒置了，正是事物的运动和变化产生了时间。所以，时间并没有解决问题，而是我们历经这一切的一个见证。但它又只是个旁观者，眼看着早生华发，眼看着长河落日，眼看着故人长绝。</p><p>依然是做很多的梦。梦见回到了初中校园，中午因为学校有事回家很晚，然后奶奶骑着三轮车到学校门口找我。梦见回到故乡，与亲人们相聚，相聊甚欢。梦见在一所教室里上课，老师讲的都是人文社科方面的知识。梦见晚上一个人走在路上，两边都是薄雾笼罩的田野，走到田野里去拍照，鞋子沾上了潮湿的泥土。梦见和认识的人争吵，然后不再联系。梦见掉了两颗牙，然后又长出新的牙齿。梦见去了缅北被坏人拿刀要挟，然后自己捡起武器把坏人都突突突了——当然这可能是乱七八糟的新闻看得多了。梦见在火车上遇到一个人很像一位表哥，聊起来才发现不是，而是另外一个曾经认识的人——但其实现实生活中根本没有这个人。梦见冬天的早上去上班，经过一片田野，远方山上都是积雪，太阳初升，山顶一片灰蒙蒙的金黄色，然后满脑子都是“苍山负雪，明烛天南”。</p><p>梦里的世界也都是悲欢离合的故事。</p><h2 id="三、自渡" tabindex="-1">三、自渡 <a class="header-anchor" href="#三、自渡" aria-label="Permalink to &quot;三、自渡&quot;">​</a></h2><p>仿佛没有经历过更热的夏天，仿佛也总会有更热的夏天。</p><p>读庄子。庄子说，无所待。徐复观说：“人生之所以受压迫，不自由，乃由于自己不能支配自己，而须受外力的牵连。受外力的牵连，即会受到外力的限制甚至支配。这种牵连，称之为‘待’。”</p><p>我之前总觉得，要放弃许多东西，才会自由。现在看起来，说放弃其实并不对，应该是要达到一种无所待的状态。</p><p>打小我就是个固执的人，哪怕表面上再随和附会，本质上也还是固执己见。所谓的不见黄河心不死，不撞南墙不回头。但一切总要去经历，很多事情也没有所谓的最优解，所以活着不就是这样摸索着前行罢了。</p><p>渡河而死，其奈公何！</p><p>如果此时你已经看到了这里，大概率会觉得不知所云，净扯淡。事实的确如此。比如我高中有个语文老师，说辛弃疾写词太喜欢用典，所以不了解的读起来会很晦涩。假如行文中隐入一些个人独有的经历典故，那么必然是一头雾水了。所以，我确实是在闲扯淡。</p>',19)]))}const m=a(i,[["render",o]]);export{c as __pageData,m as default};
